//! Cascade revocation, end to end — CONTAINMENT.
//!
//! A single reap revokes one agent, but the agents IT spawned keep running: their
//! authorizing UCAN was checked only at spawn time, so reaping the parent leaves
//! orphans. That is the blast-radius hole. A CASCADE reap closes it: reaping (or
//! breaching) an agent takes its ENTIRE spawned subtree with it, each member
//! audited, so containment is bounded and provable.
//!
//! These tests drive a REAL 3-deep lineage through `ops::spawn` +
//! `ops::delegate_spawn` (with a fake monster-guard so no real runtime is needed):
//! root spawns A (A.spawned_by = root.did); root delegate-spawns to A.did so A
//! holds attenuated spawn authority; A spawns B (B.spawned_by = A.did); A
//! delegate-spawns to B.did; B spawns C (C.spawned_by = B.did). root also spawns a
//! sibling S so the cascade's bounds can be asserted (S survives a sub-tree reap).
//!
//! Covered:
//!   (a) `reap_cascade` on the ROOT reaps the whole subtree, the audit chain shows
//!       a Reap per cascaded agent, and the chain STILL verifies.
//!   (b) `oath_breach` on the root AUTO-CASCADES the subtree (the rogue cannot
//!       leave live children) while keeping the breach record + trust dock.
//!   (c) `reap_cascade` on a MID node reaps only its sub-subtree — the root and
//!       siblings stay alive.
//!
//! Isolated in a per-pid temp `$MONSTER_GUARD_HOME`; the tests share the global
//! env so a mutex serializes them.

use std::os::unix::fs::PermissionsExt;
use std::path::PathBuf;
use std::sync::Mutex;

use a0n_auth::ucan::issue;
use a0n_auth::{Capability, IssueOptions};

use monster_swarm::audit;
use monster_swarm::budget::Caste;
use monster_swarm::ops::{self, BreachRequest, DelegateSpawnRequest, SpawnRequest, DEFAULT_GRANT_TTL_SECS};
use monster_swarm::store;

static ENV_GUARD: Mutex<()> = Mutex::new(());

/// Fake `monster-guard`: delegate + revoke exit 0; run stays alive briefly so the
/// supervisor pid is live when the ledger is saved.
fn fake_guard(dir: &PathBuf) -> PathBuf {
    let bin = dir.join("monster-guard");
    let script = "#!/bin/sh\n\
         if [ \"$1\" = \"run\" ]; then\n\
         \texec sleep 30\n\
         fi\n\
         exit 0\n";
    std::fs::write(&bin, script).unwrap();
    std::fs::set_permissions(&bin, std::fs::Permissions::from_mode(0o755)).unwrap();
    bin
}

fn fake_node(dir: &PathBuf) -> PathBuf {
    let node = dir.join("fake-node");
    std::fs::write(&node, "#!/bin/sh\nexit 0\n").unwrap();
    std::fs::set_permissions(&node, std::fs::Permissions::from_mode(0o755)).unwrap();
    node
}

struct Home {
    path: PathBuf,
}

impl Home {
    fn new(name: &str) -> Home {
        let path = std::env::temp_dir().join(format!("monster-swarm-{name}-{}", std::process::id()));
        let _ = std::fs::remove_dir_all(&path);
        std::fs::create_dir_all(&path).unwrap();
        std::env::set_var("MONSTER_GUARD_HOME", &path);
        let bindir = path.join("bin");
        std::fs::create_dir_all(&bindir).unwrap();
        std::env::set_var("MONSTER_GUARD_BIN", fake_guard(&bindir));
        fake_node(&bindir);
        std::env::set_var("MONSTER_SWARM_NODES", &bindir);
        Home { path }
    }
}

impl Drop for Home {
    fn drop(&mut self) {
        std::env::remove_var("MONSTER_GUARD_HOME");
        std::env::remove_var("MONSTER_GUARD_BIN");
        std::env::remove_var("MONSTER_SWARM_NODES");
        let _ = std::fs::remove_dir_all(&self.path);
    }
}

/// A root-issued capability granting agent/spawn + agent/reap on the fleet,
/// addressed to the root's own DID (iss == aud). reap covers oath-breach.
fn root_ucan() -> (String, String) {
    let root = store::ensure_root().expect("root");
    let caps = vec![
        Capability { can: "agent/spawn".into(), with: "agent:fleet".into(), constraints: None },
        Capability { can: "agent/reap".into(), with: "agent:fleet".into(), constraints: None },
    ];
    let ucan = issue(&root, root.did(), &caps, 3600, &IssueOptions::default()).expect("ucan");
    (ucan, root.did().to_string())
}

fn spawn_req(ucan: &str, id: &str, caps: &[&str]) -> SpawnRequest {
    SpawnRequest {
        ucan: ucan.to_string(),
        node: "fake-node".into(),
        id: Some(id.to_string()),
        caste: Caste::Scout,
        caps: caps.iter().map(|s| s.to_string()).collect(),
        lease_secs: 60,
        max_secs: None,
        grant_ttl_secs: DEFAULT_GRANT_TTL_SECS,
        node_args: vec![],
        qspec: None,
        oath: None,
        teleport: None,
    }
}

/// Read a spawned agent's own secret from its 0600 keyfile — the key it would use
/// to delegate spawn authority DOWN to a child (so the child's spawned_by chains
/// to this agent's DID, building the lineage).
fn agent_secret_hex(id: &str) -> String {
    std::fs::read_to_string(store::agent_key_path(id))
        .unwrap_or_else(|e| panic!("read {id} keyfile: {e}"))
        .trim()
        .to_string()
}

#[test]
fn reap_cascade_on_the_root_reaps_the_whole_subtree_and_audit_still_verifies() {
    let _env = ENV_GUARD.lock().unwrap_or_else(|e| e.into_inner());
    let _home = Home::new("cascade-root");

    let (ucan, root_did) = root_ucan();

    // root spawns A and the sibling S directly (both spawned_by = root.did).
    ops::spawn(spawn_req(&ucan, "A", &["net"])).expect("spawn A");
    ops::spawn(spawn_req(&ucan, "S", &["net"])).expect("spawn S");
    let a_did = store::load_fleet().find("A").expect("A").did.clone();

    // root delegates spawn authority TO A's DID (issuer = root). A now holds an
    // attenuated agent/spawn whose leaf aud is A's DID.
    let root_secret = store::root_secret_hex().expect("root secret");
    let a_token = ops::delegate_spawn(DelegateSpawnRequest {
        parent_ucan: ucan.clone(),
        issuer_secret_hex: root_secret.clone(),
        to_did: a_did.clone(),
        caps: vec!["net".into()],
        ttl_secs: 1800,
    })
    .expect("delegate to A")
    .token;

    // A spawns B under its OWN authority — B.spawned_by = A.did.
    ops::spawn(spawn_req(&a_token, "B", &["net"])).expect("A spawns B");
    let b_did = store::load_fleet().find("B").expect("B").did.clone();
    assert_eq!(
        store::load_fleet().find("B").unwrap().spawned_by,
        a_did,
        "B.spawned_by chains to A.did"
    );

    // A delegates spawn authority TO B's DID (issuer = A, read from A's keyfile).
    let a_secret = agent_secret_hex("A");
    let b_token = ops::delegate_spawn(DelegateSpawnRequest {
        parent_ucan: a_token.clone(),
        issuer_secret_hex: a_secret,
        to_did: b_did.clone(),
        caps: vec!["net".into()],
        ttl_secs: 1800,
    })
    .expect("delegate to B")
    .token;

    // B spawns C under its OWN authority — C.spawned_by = B.did.
    ops::spawn(spawn_req(&b_token, "C", &["net"])).expect("B spawns C");
    assert_eq!(
        store::load_fleet().find("C").unwrap().spawned_by,
        b_did,
        "C.spawned_by chains to B.did"
    );

    // Precondition: the lineage is fully live (A, B, C, S all present).
    let fleet = store::load_fleet();
    for id in ["A", "B", "C", "S"] {
        assert!(fleet.find(id).is_some(), "{id} live before cascade");
    }
    // The audit chain is clean before the cascade.
    assert!(audit::verify().ok, "audit clean before cascade");
    let entries_before = audit::verify().entries;

    // CASCADE-REAP the root of the lineage: A. Expect {A, B, C} reaped, S spared.
    let out = ops::reap_cascade(&ucan, "A").expect("cascade reap A");
    assert_eq!(out.count, 3, "A, B, C are the subtree of A");
    assert_eq!(out.count, out.reaped.len(), "count matches the reaped vec");
    assert_eq!(out.reaped[0], "A", "root-first: the target is first");
    let set: std::collections::HashSet<&str> = out.reaped.iter().map(|s| s.as_str()).collect();
    assert!(set.contains("A") && set.contains("B") && set.contains("C"));

    // The ledger is empty of the subtree; the sibling S survives.
    let fleet = store::load_fleet();
    for id in ["A", "B", "C"] {
        assert!(fleet.find(id).is_none(), "{id} reaped from the ledger");
        assert!(!store::agent_key_path(id).exists(), "{id} keyfile removed");
    }
    assert!(fleet.find("S").is_some(), "the sibling S is NOT in A's subtree");

    // The audit chain shows 3 NEW Reap events (one per cascaded agent), each
    // tagged cascade:true with root "A", and the chain STILL verifies.
    let report = audit::verify();
    assert!(report.ok, "the audit chain still verifies after a legitimate cascade: {}", report.reason);
    assert_eq!(
        report.entries,
        entries_before + 3,
        "exactly 3 Reap events were appended"
    );
    let reap_events: Vec<_> = audit::load()
        .into_iter()
        .filter(|e| e.kind == audit::EventKind::Reap && e.detail.get("cascade").is_some())
        .collect();
    assert_eq!(reap_events.len(), 3, "3 cascade Reap entries on the chain");
    for e in &reap_events {
        assert_eq!(e.detail["cascade"], serde_json::json!(true));
        assert_eq!(e.detail["root"], serde_json::json!("A"));
        assert_eq!(e.actor, root_did, "the reaping holder is the actor");
    }

    // An unknown target errors exactly like reap.
    let err = ops::reap_cascade(&ucan, "ghost").expect_err("unknown id errors");
    assert!(err.contains("no subagent"), "unknown id error: {err}");
}

#[test]
fn oath_breach_on_the_root_auto_cascades_the_subtree() {
    let _env = ENV_GUARD.lock().unwrap_or_else(|e| e.into_inner());
    let _home = Home::new("cascade-breach");

    let (ucan, _root_did) = root_ucan();

    // root spawns A (the rogue) + sibling S. A swears a raw-terms oath so the
    // breach record carries oath/sworn_by, and so spawned_by trust docks.
    let raw_terms = r#"{ "oath": "stay bounded", "max_caps": ["net"], "ttl_max_secs": 3600 }"#;
    ops::spawn(SpawnRequest {
        oath: Some(raw_terms.to_string()),
        ..spawn_req(&ucan, "A", &["net"])
    })
    .expect("spawn rogue A");
    ops::spawn(spawn_req(&ucan, "S", &["net"])).expect("spawn S");
    let a_did = store::load_fleet().find("A").expect("A").did.clone();

    // Build A -> B -> C below the rogue.
    let root_secret = store::root_secret_hex().expect("root secret");
    let a_token = ops::delegate_spawn(DelegateSpawnRequest {
        parent_ucan: ucan.clone(),
        issuer_secret_hex: root_secret,
        to_did: a_did.clone(),
        caps: vec!["net".into()],
        ttl_secs: 1800,
    })
    .expect("delegate to A")
    .token;
    ops::spawn(spawn_req(&a_token, "B", &["net"])).expect("A spawns B");
    let b_did = store::load_fleet().find("B").expect("B").did.clone();
    let a_secret = agent_secret_hex("A");
    let b_token = ops::delegate_spawn(DelegateSpawnRequest {
        parent_ucan: a_token,
        issuer_secret_hex: a_secret,
        to_did: b_did.clone(),
        caps: vec!["net".into()],
        ttl_secs: 1800,
    })
    .expect("delegate to B")
    .token;
    ops::spawn(spawn_req(&b_token, "C", &["net"])).expect("B spawns C");

    // BREACH the rogue root A. The breach kills A AND auto-cascades its
    // descendants (B, C) — the rogue cannot leave live children.
    let out = ops::oath_breach(BreachRequest {
        ucan: ucan.clone(),
        id: "A".into(),
        reason: "conduct: attempted exfiltration".into(),
        sig_hex: None,
    })
    .expect("breach A");
    assert_eq!(out.id, "A");

    // A, B, C are all gone; the sibling S survives (it is not in A's subtree).
    let fleet = store::load_fleet();
    for id in ["A", "B", "C"] {
        assert!(fleet.find(id).is_none(), "{id} reaped by the breach cascade");
    }
    assert!(fleet.find("S").is_some(), "the sibling S survives the breach cascade");

    // The breach record + trust dock are intact (existing behavior preserved): one
    // breach on record, and the spawner (root) now carries a reputation cost.
    let log = ops::breaches();
    assert_eq!(log.len(), 1, "exactly the rogue's breach is recorded (not the cascade)");
    assert_eq!(log[0].id, "A");
    assert!(
        ops::trusts().iter().any(|t| t.breaches >= 1),
        "the spawner's trust is docked for the breach"
    );

    // The audit chain shows the Breach plus 2 cascade Reap entries (B, C), and
    // STILL verifies.
    let report = audit::verify();
    assert!(report.ok, "audit verifies after the breach cascade: {}", report.reason);
    let cascade_reaps: Vec<_> = audit::load()
        .into_iter()
        .filter(|e| {
            e.kind == audit::EventKind::Reap
                && e.detail.get("cascade").is_some()
                && e.detail["root"] == serde_json::json!("A")
        })
        .collect();
    assert_eq!(cascade_reaps.len(), 2, "B and C were cascade-reaped on the breach");
    assert!(
        audit::load().iter().any(|e| e.kind == audit::EventKind::Breach && e.subject == "A"),
        "the rogue's own death is still a Breach event"
    );
}

#[test]
fn reap_cascade_on_a_mid_node_leaves_root_and_siblings_alive() {
    let _env = ENV_GUARD.lock().unwrap_or_else(|e| e.into_inner());
    let _home = Home::new("cascade-mid");

    let (ucan, _root_did) = root_ucan();

    // Build the same A -> B -> C lineage plus sibling S.
    ops::spawn(spawn_req(&ucan, "A", &["net"])).expect("spawn A");
    ops::spawn(spawn_req(&ucan, "S", &["net"])).expect("spawn S");
    let a_did = store::load_fleet().find("A").expect("A").did.clone();
    let root_secret = store::root_secret_hex().expect("root secret");
    let a_token = ops::delegate_spawn(DelegateSpawnRequest {
        parent_ucan: ucan.clone(),
        issuer_secret_hex: root_secret,
        to_did: a_did.clone(),
        caps: vec!["net".into()],
        ttl_secs: 1800,
    })
    .expect("delegate to A")
    .token;
    ops::spawn(spawn_req(&a_token, "B", &["net"])).expect("A spawns B");
    let b_did = store::load_fleet().find("B").expect("B").did.clone();
    let a_secret = agent_secret_hex("A");
    let b_token = ops::delegate_spawn(DelegateSpawnRequest {
        parent_ucan: a_token,
        issuer_secret_hex: a_secret,
        to_did: b_did.clone(),
        caps: vec!["net".into()],
        ttl_secs: 1800,
    })
    .expect("delegate to B")
    .token;
    ops::spawn(spawn_req(&b_token, "C", &["net"])).expect("B spawns C");

    // CASCADE-REAP the MID node B. Only its sub-subtree {B, C} dies.
    let out = ops::reap_cascade(&ucan, "B").expect("cascade reap B");
    assert_eq!(out.count, 2, "subtree(B) = {{B, C}}");
    let set: std::collections::HashSet<&str> = out.reaped.iter().map(|s| s.as_str()).collect();
    assert!(set.contains("B") && set.contains("C"));

    // The root A and the sibling S are still alive (above / beside B).
    let fleet = store::load_fleet();
    assert!(fleet.find("A").is_some(), "the root A survives a mid-node cascade");
    assert!(fleet.find("S").is_some(), "the sibling S survives a mid-node cascade");
    assert!(fleet.find("B").is_none(), "B reaped");
    assert!(fleet.find("C").is_none(), "C reaped");

    // The audit chain still verifies.
    assert!(audit::verify().ok, "audit verifies after a mid-node cascade");
}
